61	
62	    -- *** Constants ***
63	    constant EntityName_c   : string   := "olo_base_wconv_n2m";
64	    constant MaxChunkSize_c : positive := greatestCommonFactor(InWidth_g, OutWidth_g);
65	    constant ChunkSize_c    : positive := choose(UseBe_g, 8, MaxChunkSize_c);
66	    constant SrWidth_c      : positive := choose(OutWidth_g > InWidth_g, 2*OutWidth_g, OutWidth_g+InWidth_g);
67	    constant OutChunks_c    : positive := OutWidth_g / ChunkSize_c;
68	    constant InChunks_c     : positive := InWidth_g / ChunkSize_c;
69	
70	    -- *** Two Process Method ***
71	    type TwoProcess_r is record
72	        ChunkCnt    : integer range 0 to SrWidth_c / ChunkSize_c - 1;
73	        ShiftReg    : std_logic_vector(SrWidth_c - 1 downto 0);
74	        LastChunk   : std_logic_vector(SrWidth_c / ChunkSize_c - 1 downto 0);
75	        LastPending : std_logic;
76	    end record;
77	
78	    signal r, r_next : TwoProcess_r;
79	
80	begin
81	
82	    -- assertions
83	    assert (UseBe_g = false) or ((InWidth_g mod 8 = 0) and (OutWidth_g mod 8 = 0))
84	        report errorMessage(EntityName_c, "Byte Enables are only supported for byte-aligned InWidht_g and OutWidth_g")
85	        severity failure;
86	
87	    -- Implement conversion logic only if required
88	    g_convert : if OutWidth_g /= InWidth_g generate
89	
90	        p_comb : process (all) is
91	            variable v            : TwoProcess_r;
92	            variable Out_Valid_v  : std_logic;
93	            variable Offset_v     : natural range 0 to SrWidth_c - 1;
94	            variable IsLastBeat_v : std_logic;
95	        begin
96	            -- *** hold variables stable ***
97	            v := r;
98	
99	            -- Output transaction
100	            Out_Valid_v  := '0';
101	            IsLastBeat_v := or_reduce(r.LastChunk(OutChunks_c - 1 downto 0));
102	            if (r.ChunkCnt >= OutChunks_c) or (IsLastBeat_v = '1') then
103	                Out_Valid_v := '1';
104	            end if;
105	            if Out_Valid_v = '1' and Out_Ready = '1' then
106	                -- Clear after last beat
107	                if IsLastBeat_v = '1' then
108	                    v.ChunkCnt    := 0;
109	                    v.ShiftReg    := (others => '0');
110	                    v.LastChunk   := (others => '0');
111	                    v.LastPending := '0';
112	                -- Normal Operation
113	                else
114	                    v.ChunkCnt  := r.ChunkCnt - OutChunks_c;
115	                    v.ShiftReg  := zerosVector(OutWidth_g) & r.ShiftReg(r.ShiftReg'high downto OutWidth_g);
116	                    v.LastChunk := zerosVector(OutChunks_c) & r.LastChunk(r.LastChunk'high downto OutChunks_c);
117	                end if;
118	            end if;
119	            Out_Valid <= Out_Valid_v;
120	            Out_Data  <= r.ShiftReg(OutWidth_g - 1 downto 0);
121	            Out_Last  <= IsLastBeat_v;
122	            -- Output byte enables
123	            if UseBe_g = true then
124	                Out_Be <= (others => '0');
125	
126	                -- Loop through all byte-enable signals
127	                for byte in 0 to OutChunks_c-1 loop
128	                    Out_Be(byte) <= '1';
129	                    if r.LastChunk(byte) = '1' then
130	                        exit;
131	                    end if;
132	                end loop;
133	
134	            else
135	                Out_Be <= (others => '1');
136	            end if;
137	
138	            -- Shift in new data if required
139	            In_Ready <= '0';
140	            -- On last beat in blockage, do not accept data
141	            if (v.ChunkCnt < OutChunks_c) and (v.LastPending = '0') then
142	
143	                In_Ready <= not Rst;
144	                if In_Valid = '1' then
145	                    -- Insert dat ainto shift register
146	                    Offset_v                                             := v.ChunkCnt*ChunkSize_c;
147	                    v.ShiftReg(Offset_v + InWidth_g - 1 downto Offset_v) := In_Data;
148	
149	                    -- Select last chunk for byte-enables (based on byte enables)
150	                    if UseBe_g = true then
151	                        -- Check correct BE usage
152	                        assert (In_Last = '1') or (In_Be = onesVector(In_Be'length))
153	                            report errorMessage(EntityName_c, "Incomplete byte enables are only supported for last beat")
154	                            severity failure;
155	                        -- Assert last chunk on correct byte (default)
156	                        v.LastChunk(v.ChunkCnt + InChunks_c-1) := In_Last;
157	
158	                        -- Loop through all byte-enables
159	                        for byte in 0 to InChunks_c-2 loop
160	                            if In_Be(byte) = '1' and In_Be(byte+1) = '0' then
161	                                v.LastChunk(v.ChunkCnt + byte)         := In_Last; -- set last chunk
162	                                v.LastChunk(v.ChunkCnt + InChunks_c-1) := '0'; -- override default
163	                                exit;
164	                            end if;
165	                        end loop;
166	
167	                    -- Select last chunk with disabled byte-enables
168	                    else
169	                        v.LastChunk(v.ChunkCnt + InChunks_c-1) := In_Last;
170	                    end if;
171	                    v.ChunkCnt    := v.ChunkCnt + InChunks_c;
172	                    v.LastPending := In_Last;
173	                end if;
174	            end if;
175	
176	            -- *** assign signal ***
