35	
36	    -----------------------------------------------------------------------------------------------
37	    -- Constants
38	    -----------------------------------------------------------------------------------------------
39	    constant OutWidth_c  : natural := 4;
40	    constant InWidth_c   : natural := OutWidth_c*WidthRatio_g;
41	    constant ClkPeriod_c : time    := 10 ns;
42	
43	    -----------------------------------------------------------------------------------------------
44	    -- TB Defnitions
45	    -----------------------------------------------------------------------------------------------
46	    shared variable WordDelay_v : time := 0 ns;
47	
48	    -- *** Verification Compnents ***
49	    constant AxisMaster_c : axi_stream_master_t := new_axi_stream_master (
50	        data_length => InWidth_c,
51	        user_length => WidthRatio_g,
52	        stall_config => new_stall_config(0.0, 0, 0)
53	    );
54	    constant AxisSlave_c  : axi_stream_slave_t  := new_axi_stream_slave (
55	        data_length => OutWidth_c,
56	        stall_config => new_stall_config(0.0, 0, 0)
57	    );
58	
59	    function counterValue (start : integer) return std_logic_vector is
60	        variable Value_v : std_logic_vector(InWidth_c-1 downto 0);
61	    begin
62	
63	        -- Iterate through wider vector
64	        for i in 0 to WidthRatio_g-1 loop
65	            Value_v(4*i+3 downto 4*i) := toUslv(start+i, 4);
66	        end loop;
67	
68	        return Value_v;
69	    end function;
