33	architecture sim of olo_base_tdm_mux_tb is
34	
35	    -----------------------------------------------------------------------------------------------
36	    -- Constants
37	    -----------------------------------------------------------------------------------------------
38	    constant Width_c     : natural := 16;
39	    constant Channels_c  : natural := 5;
40	    constant ClkPeriod_c : time    := 10 ns;
41	
