49	        user_length => 3,
50	        stall_config => new_stall_config(0.0, 0, 0)
51	    );
52	    constant AxisSlave_c  : axi_stream_slave_t  := new_axi_stream_slave (
53	        data_length => Width_c,
54	        stall_config => new_stall_config(0.0, 0, 0)
55	    );
