62	    signal In_Valid  : std_logic                              := '0';
63	    signal In_Data   : std_logic_vector(Width_c - 1 downto 0) := (others => '0');
64	    signal In_ChSel  : std_logic_vector(2 downto 0)           := (others => '0');
65	    signal In_Last   : std_logic                              := '0';
66	    signal Out_Valid : std_logic                              := '0';
67	    signal Out_Data  : std_logic_vector(Width_c - 1 downto 0) := (others => '0');
68	    signal Out_Last  : std_logic                              := '0';
69	
70	begin
71	
72	    -----------------------------------------------------------------------------------------------
73	    -- TB Control
74	    -----------------------------------------------------------------------------------------------
75	    test_runner_watchdog(runner, 1 ms);
76	
77	    p_control : process is
78	        variable ChSel_v : integer;
79	    begin
80	        test_runner_setup(runner, runner_cfg);
81	
82	        while test_suite loop
83	
84	            -- Reset
85	            wait until rising_edge(Clk);
86	            Rst <= '1';
87	            wait for 1 us;
88	            wait until rising_edge(Clk);
89	            Rst <= '0';
90	            wait until rising_edge(Clk);
91	
92	            -- Test each channel
93	            if run("EachChannel") then
94	
95	                -- loop through samples
96	                for ch in 0 to Channels_c-1 loop
97	
98	                    -- loop through channels
99	                    for s in 0 to Channels_c-1 loop
100	                        push_axi_stream(net, AxisMaster_c, toUslv(ch*256+s, Width_c), tuser => toUslv(ch, In_ChSel'length), tlast => '0');
101	                    end loop;
102	
103	                    check_axi_stream(net, AxisSlave_c, toUslv(ch*256+ch, Width_c), tlast => '0', blocking => false, msg => "data " & integer'image(ch));
104	                    wait_until_idle(net, as_sync(AxisMaster_c));
105	                    wait for 1 us;
106	                end loop;
107	
108	            end if;
109	
110	            -- Test select sampling on first sample
111	            if run("SampleOnFirst") then
112	
113	                -- loop through samples
114	                for ch in 0 to Channels_c-1 loop
115	
116	                    -- loop through channels
117	                    for s in 0 to Channels_c-1 loop
118	                        if s = 0 then
119	                            ChSel_v := ch;
120	                        else
121	                            ChSel_v := 0;
122	                        end if;
123	                        push_axi_stream(net, AxisMaster_c, toUslv(ch*256+s, Width_c), tuser => toUslv(ChSel_v, In_ChSel'length), tlast => '0');
124	                    end loop;
125	
126	                    check_axi_stream(net, AxisSlave_c, toUslv(ch*256+ch, Width_c), tlast => '0', blocking => false, msg => "data " & integer'image(ch));
127	                    wait for 1 us;
128	                end loop;
129	
130	            end if;
131	
132	            if run("ResyncOnTlast") then
133	                -- Two samples off
134	                push_axi_stream(net, AxisMaster_c, toUslv(10, Width_c), tuser => toUslv(4, In_ChSel'length), tlast => '0');
135	                push_axi_stream(net, AxisMaster_c, toUslv(11, Width_c), tuser => toUslv(4, In_ChSel'length), tlast => '1');
136	
137	                -- Resynchronize (with t-last set)
138	                for spl in 0 to 3 loop
139	
140	                    -- loop through channels
141	                    for ch in 0 to Channels_c-1 loop
142	                        push_axi_stream(net, AxisMaster_c, toUslv(spl*32+ch, Width_c),
143	                            tuser => toUslv(3, In_ChSel'length),
144	                            tlast => choose(ch=Channels_c-1, '1', '0'));
145	                    end loop;
146	
147	                    check_axi_stream(net, AxisSlave_c, toUslv(spl*32+3, Width_c), tlast => '1', blocking => false, msg => "data " & integer'image(spl));
148	                end loop;
149	
150	                -- Test if t-last stays cleared if unused
151	                for spl in 0 to 3 loop
152	
